        used: snapshot.primary.used,
        limit: snapshot.primary.limit,
        remaining: snapshot.primary.remaining,
        unit: 'requests',
        resetAt: snapshot.primary.resetAt,
        available: true
      });
    }
    return buildUnifiedQuotaPayload({ available: false });
  }
  return buildUnifiedQuotaPayload({ available: false });
}

